import pytest

def test_missing_authorization_header_returns_401(
    fhir_base_url, http_client
):
    resp = http_client.get(
        f"{fhir_base_url}/AuditEvent",
        params={"organization": "ORG-001"},
        # deliberately omit Authorization header
    )

    assert resp.status_code == 401, (
        f"Expected 401 for missing token, got {resp.status_code}"
    )
    body = resp.json()
    assert body.get("resourceType") == "OperationOutcome"
    issues = body.get("issue", [])
    valid_codes = {"login", "unknown", "security"}
    assert any(i.get("code") in valid_codes for i in issues), (
        f"Unexpected issue codes: {[i.get('code') for i in issues]}"
    )
    assert "entry" not in body, "No Bundle entries should be present"
